{
  "terms": [
    {
      "term": "Zs",
      "simpleDefinition": "The total resistance of the entire earth loop path, including both the supplier's equipment and the internal installation wiring.",
      "anchor": "The 'Total' impedance that determines if a fuse will blow fast enough during a fault.",
      "misconception": "Thinking Zs only refers to the earth wire; it actually includes the line conductor and the external supply path too."
    },
    {
      "term": "Ze",
      "simpleDefinition": "The resistance of the fault path outside of the installation, provided by the electricity supplier.",
      "anchor": "The 'External' impedance measured at the origin of the installation.",
      "misconception": "Believing the electrician can lower this value; Ze is determined by the supplier's cables and transformer."
    },
    {
      "term": "R1",
      "simpleDefinition": "The resistance of the line (phase) conductor from the consumer unit to the point of the fault.",
      "anchor": "The 'Outgoing' leg of the fault current journey.",
      "misconception": "Confusing R1 with the total circuit resistance; it only accounts for the line wire."
    },
    {
      "term": "R2",
      "simpleDefinition": "The resistance of the Circuit Protective Conductor (CPC) from the point of the fault back to the main earthing terminal.",
      "anchor": "The 'Return' leg of the fault current within the building.",
      "misconception": "Thinking R2 is the same as the main earthing conductor; R2 is specific to the individual circuit's earth wire."
    },
    {
      "term": "MET",
      "simpleDefinition": "The Main Earthing Terminal; the central point where all earthing and bonding conductors are connected.",
      "anchor": "The 'Hub' where the internal house earthing meets the supplier's external earth.",
      "misconception": "Thinking the MET is just a junction box; it is a critical safety connection point for the entire installation."
    },
    {
      "term": "Supplier Earth Return Path",
      "simpleDefinition": "The physical route (cables or the ground itself) that fault current takes to get from the installation back to the supply transformer.",
      "anchor": "The 'Road Home' for electricity to complete its circuit back to the source.",
      "misconception": "Believing electricity just 'stops' at the earth rod or ground; it must always return to the transformer to complete the loop."
    }
  ],
  "anchorPhrases": [
    "Zs = Ze + (R1 + R2)",
    "The fault current must travel in a complete loop to trigger a protective device.",
    "Ze is the foundation of the loop provided by the network distributor.",
    "R1 and R2 represent the internal resistance of the specific circuit."
  ],
  "misconceptionTargets": [
    "Electricity does not disappear into the ground; it returns to the transformer.",
    "The earth loop is a circuit, not a one-way street.",
    "You cannot calculate Zs accurately without including the line conductor (R1)."
  ]
}

{
  "teachChecks": [
    {
      "title": "The Concept of the Loop",
      "basicQuestions": [
        {
          "questionText": "To which specific source must fault current always return to complete its circuit?",
          "answerGuidance": [
            "Supply transformer",
            "Transformer"
          ],
          "hint": "This is the component at the start of the supply chain where the electricity originates.",
          "sourceTeachingPointIds": [
            "TP1"
          ]
        },
        {
          "questionText": "What technical symbol is used to represent the total resistance of the entire earth loop path?",
          "answerGuidance": [
            "Zs"
          ],
          "hint": "It is a capital Z followed by a lowercase s.",
          "sourceTeachingPointIds": [
            "TP4"
          ]
        },
        {
          "questionText": "What is the primary safety reason for maintaining a low Zs value in a circuit?",
          "answerGuidance": [
            "Ensure protective devices operate",
            "Trip the circuit breaker",
            "Blow the fuse"
          ],
          "hint": "Think about what needs to happen to the power if a fault occurs.",
          "sourceTeachingPointIds": [
            "TP5"
          ]
        }
      ],
      "deeperQuestionText": "Explain why the term 'loop' is used to describe the path of fault current rather than describing the earth as a simple destination.",
      "deeperAnswerGuidance": [
        "Electricity must return to its source to flow",
        "The path starts and ends at the transformer",
        "It forms a complete electrical circuit",
        "Current does not just stop at the point of the fault"
      ],
      "deeperSourceTeachingPointIds": [
        "TP1",
        "TP3"
      ],
      "hint": "Consider what is required for any electrical current to flow continuously."
    },
    {
      "title": "External Path Components",
      "basicQuestions": [
        {
          "questionText": "What abbreviation represents the external earth loop impedance provided by the supplier?",
          "answerGuidance": [
            "Ze"
          ],
          "hint": "The 'e' stands for external.",
          "sourceTeachingPointIds": [
            "TP1"
          ]
        },
        {
          "questionText": "At what specific point in an electrical installation is the external impedance measured?",
          "answerGuidance": [
            "Origin of the installation",
            "Main intake"
          ],
          "hint": "This is where the supplier's cables first enter the building.",
          "sourceTeachingPointIds": [
            "TP4"
          ]
        },
        {
          "questionText": "What is the name of the physical route provided by the network distributor for fault current to return to the source?",
          "answerGuidance": [
            "Supplier earth return path"
          ],
          "hint": "It is the path back home provided by the company that supplies the power.",
          "sourceTeachingPointIds": [
            "TP3"
          ]
        }
      ],
      "deeperQuestionText": "Why must an electrician measure Ze at the origin of the installation if they have no direct control over the supplier's equipment?",
      "deeperAnswerGuidance": [
        "Ze is the starting resistance for the whole loop",
        "It is needed to calculate the total Zs",
        "It ensures the supplier's path is adequate before adding internal wiring",
        "It forms the foundation of the safety calculation"
      ],
      "deeperSourceTeachingPointIds": [
        "TP4",
        "TP5"
      ],
      "hint": "Think about how the external resistance affects the final total resistance of the circuit."
    },
    {
      "title": "Internal Path Components",
      "basicQuestions": [
        {
          "questionText": "What label is used for the resistance of the line conductor within an installation?",
          "answerGuidance": [
            "R1"
          ],
          "hint": "This is the 'outbound' part of the internal circuit.",
          "sourceTeachingPointIds": [
            "TP1"
          ]
        },
        {
          "questionText": "What does the abbreviation R2 represent in the context of an earth loop path?",
          "answerGuidance": [
            "Circuit Protective Conductor resistance",
            "CPC resistance"
          ],
          "hint": "This is the resistance of the earth wire for that specific circuit.",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        },
        {
          "questionText": "What is the name of the central hub where internal earthing conductors connect to the supplier's earth?",
          "answerGuidance": [
            "Main Earthing Terminal",
            "MET"
          ],
          "hint": "It is the main terminal for all earthing connections.",
          "sourceTeachingPointIds": [
            "TP3"
          ]
        }
      ],
      "deeperQuestionText": "How does the MET act as a critical junction between the work of the electrician and the network distributor?",
      "deeperAnswerGuidance": [
        "It bridges the internal R1/R2 path and the external Ze path",
        "It is the connection point for all earthing and bonding",
        "It allows internal fault current to reach the supplier return path",
        "It is the central hub for the entire earthing system"
      ],
      "deeperSourceTeachingPointIds": [
        "TP3",
        "TP4"
      ],
      "hint": "Focus on the MET's role as a meeting point for different parts of the loop."
    },
    {
      "title": "The Total Path (Zs)",
      "basicQuestions": [
        {
          "questionText": "What is the standard formula used to determine the total earth loop impedance?",
          "answerGuidance": [
            "Zs = Ze + (R1 + R2)"
          ],
          "hint": "You must add the external resistance to the internal line and earth resistances.",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        },
        {
          "questionText": "If the Zs value of a circuit is too high, what happens to the level of fault current that can flow?",
          "answerGuidance": [
            "It decreases",
            "It is too low"
          ],
          "hint": "High resistance restricts the flow of current.",
          "sourceTeachingPointIds": [
            "TP4"
          ]
        },
        {
          "questionText": "Which set of regulations defines the maximum allowable disconnection times for a circuit?",
          "answerGuidance": [
            "BS 7671"
          ],
          "hint": "These are the 'Wiring Regulations' used in the UK.",
          "sourceTeachingPointIds": [
            "TP4"
          ]
        }
      ],
      "deeperQuestionText": "Why would a circuit with a very high Zs value be considered a fire or shock risk even if the fuse is the correct size?",
      "deeperAnswerGuidance": [
        "The fault current will be too low to trip the device instantly",
        "The protective device may not disconnect within BS 7671 time limits",
        "Current will continue to flow through the fault",
        "The high resistance prevents the rapid operation of the fuse or breaker"
      ],
      "deeperSourceTeachingPointIds": [
        "TP4",
        "TP5"
      ],
      "hint": "Consider the relationship between resistance, current, and the speed of the protective device."
    }
  ]
}

